
UPDATE conteudos 
SET video_url = 'https://www.youtube.com/watch?v=LSMV8S-Zd8c',
    conteudo_texto = '<h2>Contabilidade de Custos</h2><p>Custeio, formação de preços e análise de custos para concursos.</p><h3>📘 Conceitos Fundamentais</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Termo</th><th style=''padding:10px;border:1px solid #ddd;''>Definição</th><th style=''padding:10px;border:1px solid #ddd;''>Exemplo</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Gasto</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Todo sacrifício financeiro</td><td style=''padding:10px;border:1px solid #ddd;''>Qualquer desembolso</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Custo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Gasto na produção</td><td style=''padding:10px;border:1px solid #ddd;''>Matéria-prima, MOD</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Despesa</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Gasto administrativo/comercial</td><td style=''padding:10px;border:1px solid #ddd;''>Aluguel escritório, marketing</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Investimento</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Gasto ativado (benefício futuro)</td><td style=''padding:10px;border:1px solid #ddd;''>Máquinas, estoques</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Perda</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Gasto involuntário/anormal</td><td style=''padding:10px;border:1px solid #ddd;''>Incêndio, roubo</td></tr></table></div><h3>📊 Classificação dos Custos</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:250px;background:#d4edda;padding:15px;border-radius:8px;''><h4>Quanto à Identificação</h4><ul><li><strong>Direto:</strong> Identificável ao produto → Matéria-prima, MOD</li><li><strong>Indireto:</strong> Precisa de rateio → Aluguel fábrica, energia</li></ul></div><div style=''flex:1;min-width:250px;background:#fff3cd;padding:15px;border-radius:8px;''><h4>Quanto ao Volume</h4><ul><li><strong>Variável:</strong> Muda com produção → Matéria-prima</li><li><strong>Fixo:</strong> Não muda com produção → Aluguel, salário gerente</li></ul></div></div><h3>🎯 Métodos de Custeio</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Método</th><th style=''padding:10px;border:1px solid #ddd;''>O que considera</th><th style=''padding:10px;border:1px solid #ddd;''>Uso</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Absorção</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Custos fixos + variáveis</td><td style=''padding:10px;border:1px solid #ddd;''>Obrigatório fiscal (DRE)</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Variável/Direto</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Apenas custos variáveis</td><td style=''padding:10px;border:1px solid #ddd;''>Gerencial, margem contribuição</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>ABC</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Custos por atividades</td><td style=''padding:10px;border:1px solid #ddd;''>Empresas com alto CIF</td></tr></table></div><h3>💰 Margem de Contribuição</h3><div style=''background:#d4edda;padding:20px;border-radius:8px;margin:15px 0;text-align:center;''><h3 style=''color:#28a745;''>MC = Preço de Venda - Custos Variáveis</h3><p>Quanto cada unidade contribui para cobrir custos fixos e gerar lucro</p></div><h3>📈 Ponto de Equilíbrio</h3><div style=''background:#fff3cd;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #ffc107;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#ffc107;''><th style=''padding:10px;border:1px solid #ddd;''>Tipo</th><th style=''padding:10px;border:1px solid #ddd;''>Fórmula</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>PE Contábil</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Custos Fixos ÷ MC unitária</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>PE Econômico</strong></td><td style=''padding:10px;border:1px solid #ddd;''>(CF + Lucro desejado) ÷ MC</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>PE Financeiro</strong></td><td style=''padding:10px;border:1px solid #ddd;''>(CF - Depreciação) ÷ MC</td></tr></table></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>Cesgranrio adora cobrar: <strong>Custeio por Absorção é obrigatório para fins fiscais</strong>, enquanto Custeio Variável é usado para decisões gerenciais!</p></div>'
WHERE titulo = 'Resumo: Contabilidade de Custos';

UPDATE conteudos 
SET video_url = 'https://www.youtube.com/watch?v=T1LVVzJ0IWc',
    conteudo_texto = '<h2>Análise de Balanços</h2><p>Indicadores financeiros e econômicos para avaliar a saúde das empresas.</p><h3>📊 Tipos de Análise</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;text-align:center;''><strong>📏 Vertical</strong><p>Participação % de cada conta no total</p></div><div style=''flex:1;min-width:200px;background:#fff3cd;padding:15px;border-radius:8px;text-align:center;''><strong>📈 Horizontal</strong><p>Evolução das contas ao longo do tempo</p></div><div style=''flex:1;min-width:200px;background:#d1ecf1;padding:15px;border-radius:8px;text-align:center;''><strong>🔢 Por Índices</strong><p>Indicadores de desempenho</p></div></div><h3>💧 Indicadores de Liquidez</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><p><em>Capacidade de pagar dívidas</em></p><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Índice</th><th style=''padding:10px;border:1px solid #ddd;''>Fórmula</th><th style=''padding:10px;border:1px solid #ddd;''>Ideal</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Liquidez Corrente</strong></td><td style=''padding:10px;border:1px solid #ddd;''>AC ÷ PC</td><td style=''padding:10px;border:1px solid #ddd;''>> 1</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Liquidez Seca</strong></td><td style=''padding:10px;border:1px solid #ddd;''>(AC - Estoques) ÷ PC</td><td style=''padding:10px;border:1px solid #ddd;''>> 1</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Liquidez Imediata</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Disponível ÷ PC</td><td style=''padding:10px;border:1px solid #ddd;''>Varia</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Liquidez Geral</strong></td><td style=''padding:10px;border:1px solid #ddd;''>(AC + RLP) ÷ (PC + PNC)</td><td style=''padding:10px;border:1px solid #ddd;''>> 1</td></tr></table></div><h3>⚖️ Indicadores de Endividamento</h3><div style=''background:#f8d7da;padding:15px;border-radius:8px;margin:15px 0;''><p><em>Estrutura de capital e dependência de terceiros</em></p><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#dc3545;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Índice</th><th style=''padding:10px;border:1px solid #ddd;''>Fórmula</th><th style=''padding:10px;border:1px solid #ddd;''>Interpretação</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Endividamento Geral</strong></td><td style=''padding:10px;border:1px solid #ddd;''>(PC + PNC) ÷ Ativo Total</td><td style=''padding:10px;border:1px solid #ddd;''>% financiado por terceiros</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Composição do Endiv.</strong></td><td style=''padding:10px;border:1px solid #ddd;''>PC ÷ (PC + PNC)</td><td style=''padding:10px;border:1px solid #ddd;''>% dívidas curto prazo</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Participação Cap. Terceiros</strong></td><td style=''padding:10px;border:1px solid #ddd;''>(PC + PNC) ÷ PL</td><td style=''padding:10px;border:1px solid #ddd;''>Terceiros vs próprio</td></tr></table></div><h3>💰 Indicadores de Rentabilidade</h3><div style=''background:#d4edda;padding:15px;border-radius:8px;margin:15px 0;''><p><em>Capacidade de gerar lucro</em></p><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Índice</th><th style=''padding:10px;border:1px solid #ddd;''>Fórmula</th><th style=''padding:10px;border:1px solid #ddd;''>Mede</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>ROE</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Lucro Líquido ÷ PL</td><td style=''padding:10px;border:1px solid #ddd;''>Retorno para acionistas</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>ROA</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Lucro Líquido ÷ Ativo Total</td><td style=''padding:10px;border:1px solid #ddd;''>Retorno sobre ativos</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Margem Líquida</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Lucro Líquido ÷ Receita</td><td style=''padding:10px;border:1px solid #ddd;''>% lucro por venda</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Margem Bruta</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Lucro Bruto ÷ Receita</td><td style=''padding:10px;border:1px solid #ddd;''>Eficiência operacional</td></tr></table></div><h3>🔄 Indicadores de Atividade</h3><div style=''background:#fff3cd;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#ffc107;''><th style=''padding:10px;border:1px solid #ddd;''>Índice</th><th style=''padding:10px;border:1px solid #ddd;''>O que mede</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Giro do Ativo</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Receita ÷ Ativo (eficiência dos ativos)</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>PMR</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Prazo Médio de Recebimento</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>PMP</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Prazo Médio de Pagamento</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>PME</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Prazo Médio de Estocagem</td></tr></table></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>Memorize: <strong>ROE = Margem × Giro × Alavancagem</strong> (Fórmula DuPont). Cesgranrio adora cobrar essa decomposição!</p></div>'
WHERE titulo = 'Resumo: Análise de Balanços';
